urlset:

  {{ SITEURL }}/
  weekly

{% for article in articles %}

  {{ SITEURL }}/{{ article.url }}
  {{ (article.modified or article.date).strftime('%Y-%m-%d') }}
  monthly

{% endfor %}
{% for page in pages %}

  {{ SITEURL }}/{{ page.url }}
  {% if page.modified or page.date %}{{ (page.modified or page.date).strftime('%Y-%m-%d') }}{% endif %}
  monthly

{% endfor %}
{% for tag, _ in tags %}

  {{ SITEURL }}/{{ tag.url }}
  weekly

{% endfor %}

  {{ SITEURL }}/archives
  weekly
